import mplfinance as mpfimport matplotlib.pyplot as pltimport matplotlib.backends.backend_agg as aggimport pygamedef draw_graph(df, plot_type="candle", dark_mode=False):    """    Draw a financial chart using mplfinance and convert it into a Pygame surface.    """    if df.empty:        surface = pygame.Surface((800, 500))        background = (20, 20, 20) if dark_mode else (240, 240, 240)        text_color = (255, 255, 255) if dark_mode else (0, 0, 0)        surface.fill(background)        font = pygame.font.Font(None, 32)        text = font.render("No data available", True, text_color)        text_rect = text.get_rect(center=(400, 250))        surface.blit(text, text_rect)        return surface    style = "nightclouds" if dark_mode else "charles"    fig, _ = mpf.plot(        df,        type=plot_type,        style=style,        returnfig=True,        figsize=(8, 5),        warn_too_much_data=100000,    )    canvas = agg.FigureCanvasAgg(fig)    canvas.draw()    renderer = canvas.get_renderer()    raw_data = renderer.buffer_rgba()    size = canvas.get_width_height()    surface = pygame.image.frombuffer(bytes(raw_data), size, "RGBA")    # Close the matplotlib figure to avoid memory build-up.    plt.close(fig)    return surface